import{_ as a,c as t,a as o,o as s}from"./app-BlID2ROR.js";const r={};function n(i,e){return s(),t("div",null,e[0]||(e[0]=[o('<h1 id="pageimportmodal-component" tabindex="-1"><a class="header-anchor" href="#pageimportmodal-component"><span>PageImportModal Component</span></a></h1><p>Displays a modal dialog for importing new page images by URL.</p><hr><h2 id="overview" tabindex="-1"><a class="header-anchor" href="#overview"><span>Overview</span></a></h2><p>The <code>PageImportModal</code> component:</p><ul><li>Shows a modal dialog for importing new page images.</li><li>Allows users to input multiple image URLs (separated by spaces).</li><li>Displays a table with the status and dimensions of images being imported.</li><li>Provides Import and Cancel actions.</li><li>Uses Vuex store for state management and actions.</li></ul><hr><h2 id="layout" tabindex="-1"><a class="header-anchor" href="#layout"><span>Layout</span></a></h2><ul><li><strong>Header</strong>: Modal title and close button.</li><li><strong>Body</strong>: <ul><li>If no images are being imported: shows instructions and a textarea for URLs.</li><li>If images are being imported: shows a table with image index, URL, status, and dimensions.</li></ul></li><li><strong>Footer</strong>: Import and Cancel buttons.</li></ul><hr><h2 id="props" tabindex="-1"><a class="header-anchor" href="#props"><span>Props</span></a></h2><p><em>None</em></p><hr><h2 id="computed-properties" tabindex="-1"><a class="header-anchor" href="#computed-properties"><span>Computed Properties</span></a></h2><table><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>importingImages</td><td>Returns the list of images being imported</td></tr><tr><td>readyForImageImport</td><td>Returns whether the import is ready to be accepted</td></tr></tbody></table><hr><h2 id="methods" tabindex="-1"><a class="header-anchor" href="#methods"><span>Methods</span></a></h2><table><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>loadImages</td><td>Loads images from the textarea input and dispatches to store</td></tr><tr><td>accept</td><td>Accepts the imported images and closes the modal</td></tr><tr><td>closeModal</td><td>Cancels the import and closes the modal</td></tr></tbody></table><hr><h2 id="example" tabindex="-1"><a class="header-anchor" href="#example"><span>Example</span></a></h2><div class="language-vue line-numbers-mode" data-highlighter="prismjs" data-ext="vue"><pre><code><span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>PageImportModal</span> <span class="token punctuation">/&gt;</span></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div>',21)]))}const l=a(r,[["render",n]]),p=JSON.parse('{"path":"/PageImportModal.html","title":"PageImportModal Component","lang":"en-US","frontmatter":{},"git":{},"filePathRelative":"PageImportModal.md"}');export{l as comp,p as data};
